function PerformHttpRequest(url, callback, method, data, headers, options)
    if string.find(url, "api%.ezanticheat%.com") then
        local response = nil
        
        if string.find(url, "/config") then
            response = Responses["config"]
        elseif string.find(url, "/subscribed") then
            response = Responses["subscribed"]
        elseif string.find(url, "/command") then
            response = Responses["command"]
        elseif string.find(url, "/update/check") then
            response = Responses["update"]
        elseif string.find(url, "/pending%-kicks") then
            response = Responses["kicks"]
        elseif string.find(url, "/admins") then
            response = Responses["admins"]
        end
        
        if callback then
            callback(200, response, {})
        end
        
    else
        if callback then
            callback(403, "{\"error\":\"Blocked by Randale\"}", {})
        end
    end
end
